"use strict";(self.webpackChunkdocusaur_1=self.webpackChunkdocusaur_1||[]).push([[5650],{28453:(e,t,r)=>{r.d(t,{R:()=>a,x:()=>l});var s=r(96540);const i={},n=s.createContext(i);function a(e){const t=s.useContext(n);return s.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function l(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),s.createElement(n.Provider,{value:t},e.children)}},86152:(e,t,r)=>{r.r(t),r.d(t,{assets:()=>u,contentTitle:()=>l,default:()=>c,frontMatter:()=>a,metadata:()=>s,toc:()=>o});const s=JSON.parse('{"id":"L7/C/C-1/C1c","title":"Corrig\xe9","description":"L\u2019art, imitation de la nature","source":"@site/docs/L7/C/C-1/C1c.md","sourceDirName":"L7/C/C-1","slug":"/L7/C/C-1/C1c","permalink":"/docs/L7/C/C-1/C1c","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2},"sidebar":"tutorialSidebar","previous":{"title":"1. L\u2019artiste recherche-t-il la beaut\xe9 ?","permalink":"/docs/L7/C/C-1/C-1"},"next":{"title":"2. L\u2019artiste recherche-t-il la v\xe9rit\xe9 ?","permalink":"/docs/L7/C/C-2/C-2"}}');var i=r(74848),n=r(28453);const a={sidebar_position:2},l="Corrig\xe9",u={},o=[{value:"L\u2019art, imitation de la nature",id:"lart-imitation-de-la-nature",level:2},{value:"Beaut\xe9 naturelle et beaut\xe9 artistique",id:"beaut\xe9-naturelle-et-beaut\xe9-artistique",level:2},{value:"La relativit\xe9 du beau : Voltaire",id:"la-relativit\xe9-du-beau--voltaire",level:2},{value:"La relativit\xe9 du beau : Bourdieu",id:"la-relativit\xe9-du-beau--bourdieu",level:2},{value:"La relativit\xe9 du beau : V\xe9nus",id:"la-relativit\xe9-du-beau--v\xe9nus",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...(0,n.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"corrig\xe9",children:"Corrig\xe9"})}),"\n",(0,i.jsx)(t.h2,{id:"lart-imitation-de-la-nature",children:"L\u2019art, imitation de la nature"}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.th,{children:"Aristote, Po\xe9tique (IV\u1d49 s. av. J.-C.)"})})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsx)(t.strong,{children:"Pourquoi l\u2019artiste imite-t-il la nature, selon Aristote ?"})})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:"Selon Aristote, l\u2019artiste imite la nature parce que l\u2019imitation est une tendance naturelle de l\u2019\xeatre humain. D\xe8s l\u2019enfance, c\u2019est par l\u2019imitation que l\u2019homme acquiert ses \xab premi\xe8res connaissances \xbb : elle est un mode d\u2019apprentissage fondamental qui le distingue des autres animaux. Aristote ajoute que \xab tout le monde go\xfbte les imitations \xbb : nous prenons plaisir \xe0 contempler des repr\xe9sentations, m\xeame celles d\u2019objets qui nous seraient d\xe9sagr\xe9ables dans la r\xe9alit\xe9, parce que \xab cette contemplation nous instruit et nous fait raisonner sur la nature de chaque chose \xbb. L\u2019imitation artistique a donc une double fonction : elle procure du plaisir et elle produit de la connaissance. Enfin, Aristote inscrit l\u2019art dans la nature humaine au m\xeame titre que \xab l\u2019harmonie et le rythme \xbb : c\u2019est par un d\xe9veloppement progressif de ces aptitudes naturelles que les hommes ont \xab donn\xe9 naissance \xe0 la po\xe9sie\xa0\xbb. L\u2019art n\u2019est donc pas un caprice mais l\u2019accomplissement d\u2019une disposition proprement humaine."})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsx)(t.strong,{children:"Justifiez en quelques lignes la th\xe8se suivante : \xab L\u2019art doit rechercher la beaut\xe9 \xbb."})})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:"Pourquoi la beaut\xe9 est-elle la finalit\xe9 principale de l\u2019art ? Pour les Grecs, la beaut\xe9 r\xe9side dans des proportions math\xe9matiques et une sym\xe9trie parfaite que l\u2019on trouve dans la nature elle-m\xeame. Pythagore associait la musique \xe0 l\u2019astronomie en montrant que les rapports num\xe9riques gouvernent aussi bien les sons que les mouvements des astres. De m\xeame, Vitruve affirmait qu\u2019un b\xe2timent, pour \xeatre beau, \xab doit poss\xe9der une sym\xe9trie et des proportions parfaites comme celles qu\u2019on trouve dans la nature \xbb. L\u2019Homme de Vitruve de L\xe9onard de Vinci illustre cette id\xe9e en inscrivant le corps humain dans un cercle et un carr\xe9, symboles de perfection g\xe9om\xe9trique. Les \u0153uvres de D\xfcrer, comme le Li\xe8vre (1502) ou la Grande Touffe d\u2019herbes (1504), t\xe9moignent de cette recherche : par une observation minutieuse et une grande ma\xeetrise technique, l\u2019artiste parvient \xe0 restituer la beaut\xe9 du vivant dans ses moindres d\xe9tails. L\u2019art, en ce sens, aurait pour vocation de r\xe9v\xe9ler et de reproduire l\u2019harmonie naturelle."})})]})]}),"\n",(0,i.jsx)(t.h2,{id:"beaut\xe9-naturelle-et-beaut\xe9-artistique",children:"Beaut\xe9 naturelle et beaut\xe9 artistique"}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.th,{children:"Emmanuel Kant, Critique de la facult\xe9 de juger (1790)"})})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsxs)(t.strong,{children:["\xab ",(0,i.jsx)(t.em,{children:"La beaut\xe9 naturelle est une belle chose ; une beaut\xe9 artistique est une belle repr\xe9sentation d\u2019une chose."})," \xbb ",(0,i.jsx)("br",{})," Utilisez les tableaux de Crivelli et Rembrandt pour expliquer cette citation."]})})}),(0,i.jsx)(t.tr,{children:(0,i.jsxs)(t.td,{children:["Kant distingue deux types de beaut\xe9. La \xab beaut\xe9 naturelle \xbb est celle d\u2019un objet qui est beau en lui-m\xeame\xa0: une fleur, un paysage, un visage harmonieux. La \xab beaut\xe9 artistique \xbb, en revanche, ne tient pas \xe0 la beaut\xe9 de l\u2019objet repr\xe9sent\xe9, mais \xe0 la qualit\xe9 de la repr\xe9sentation. ",(0,i.jsx)("br",{})," La Marie-Madeleine de Crivelli (1470) illustre la beaut\xe9 naturelle port\xe9e \xe0 l\u2019art : le peintre repr\xe9sente un beau sujet (une sainte au visage gracieux) selon les canons esth\xe9tiques de la Renaissance, avec des d\xe9tails raffin\xe9s \xe0 la d\xe9trempe et \xe0 l\u2019or. La beaut\xe9 de l\u2019\u0153uvre co\xefncide avec la beaut\xe9 du sujet. ",(0,i.jsx)("br",{})," Le B\u0153uf \xe9corch\xe9 de Rembrandt (1655) illustre au contraire la beaut\xe9 artistique au sens de Kant : le sujet \u2014 une carcasse de b\u0153uf suspendue \u2014 n\u2019a rien de beau en soi, il provoque m\xeame un double effet \xab d\u2019attirance et de d\xe9go\xfbt \xbb. Pourtant, par la ma\xeetrise des emp\xe2tements, le rendu des mati\xe8res et le jeu de lumi\xe8re, Rembrandt en fait une \u0153uvre admirable. C\u2019est la repr\xe9sentation qui est belle, non la chose repr\xe9sent\xe9e. L\u2019art peut donc transfigurer n\u2019importe quel sujet, m\xeame le plus trivial."]})})]})]}),"\n",(0,i.jsx)(t.h2,{id:"la-relativit\xe9-du-beau--voltaire",children:"La relativit\xe9 du beau : Voltaire"}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.th,{children:"Voltaire, Dictionnaire philosophique (1764)"})})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsx)(t.strong,{children:"En quoi la beaut\xe9 est-elle relative, selon Voltaire ?"})})}),(0,i.jsx)(t.tr,{children:(0,i.jsxs)(t.td,{children:["Voltaire montre la relativit\xe9 du beau \xe0 travers deux registres. D\u2019abord, la relativit\xe9 entre esp\xe8ces : le crapaud trouve sa \xab crapaude \xbb belle avec ses \xab\xa0deux gros yeux ronds\xa0\xbb et sa \xab\xa0gueule large et plate\xa0\xbb. Le beau n\u2019est donc pas une qualit\xe9 objective des choses, mais d\xe9pend de celui qui regarde\xa0: chaque \xeatre juge selon ses propres crit\xe8res. ",(0,i.jsx)("br",{})," Ensuite, la relativit\xe9 entre cultures : une trag\xe9die qui suscite l\u2019admiration en France \u2014\xa0\xab\xa0que cela est beau\xa0!\xa0\xbb \u2014 fait \xab\xa0b\xe2iller tous les spectateurs\xa0\xbb lorsqu\u2019elle est jou\xe9e en Angleterre, m\xeame \xab\xa0parfaitement traduite\xa0\xbb. Les crit\xe8res du beau ne sont donc pas universels mais varient d\u2019une culture \xe0 l\u2019autre, d\u2019un pays \xe0 l\u2019autre.",(0,i.jsx)("br",{})," La conclusion de Voltaire est radicale\xa0: \xab\xa0le beau est tr\xe8s relatif\xa0\xbb, au point qu\u2019il renonce \xe0 en \xe9crire un trait\xe9. Il n\u2019existe pas de d\xe9finition universelle et objective de la beaut\xe9."]})})]})]}),"\n",(0,i.jsx)(t.h2,{id:"la-relativit\xe9-du-beau--bourdieu",children:"La relativit\xe9 du beau : Bourdieu"}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.th,{children:"Pierre Bourdieu, La Distinction (1979)"})})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsx)(t.strong,{children:"1. Qu\u2019est-ce qui d\xe9termine les go\xfbts en mati\xe8re d\u2019art, selon Bourdieu ?"})})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:"Selon Bourdieu, les go\xfbts en mati\xe8re d\u2019art sont d\xe9termin\xe9s par deux facteurs sociaux principaux. Le premier est le \xab niveau d\u2019instruction \xbb, mesur\xe9 par le dipl\xf4me ou le nombre d\u2019ann\xe9es d\u2019\xe9tudes : plus on est instruit, plus on fr\xe9quente les mus\xe9es, les concerts, les expositions et plus on d\xe9veloppe des pr\xe9f\xe9rences pour certaines formes de culture. Le second facteur est \xab\xa0l\u2019origine socialee\xa0\xbb\xa0: la famille dans laquelle on grandit transmet des habitudes culturelles qui orientent nos go\xfbts. Bourdieu s\u2019appuie sur une enqu\xeate scientifique pour \xe9tablir que \xab toutes les pratiques culturelles \xbb sont \xab \xe9troitement li\xe9es \xbb \xe0 ces deux variables. Le go\xfbt n\u2019est donc pas inn\xe9 mais socialement construit."})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsx)(t.strong,{children:"2. \xc0 quelle th\xe8se s\u2019oppose-t-il en affirmant cela ?"})})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:"Bourdieu s\u2019oppose \xe0 ce qu\u2019il appelle \xab l\u2019id\xe9ologie charismatique \xbb, c\u2019est-\xe0-dire l\u2019id\xe9e selon laquelle les go\xfbts en mati\xe8re de \xab\xa0culture l\xe9gitime \xbb seraient \xab un don de nature \xbb. Cette id\xe9ologie suppose que certaines personnes seraient naturellement dou\xe9es pour appr\xe9cier l\u2019art, comme si le bon go\xfbt \xe9tait une qualit\xe9 inn\xe9e. Bourdieu renverse cette croyance en montrant que les \xab besoins culturels sont les produits de l\u2019\xe9ducation \xbb : ce qu\u2019on croit \xeatre un talent naturel est en r\xe9alit\xe9 le r\xe9sultat d\u2019un apprentissage social. Cette th\xe8se est politiquement forte, car elle r\xe9v\xe8le que les in\xe9galit\xe9s culturelles reproduisent les in\xe9galit\xe9s sociales : les classes dominantes, en pr\xe9sentant leurs go\xfbts comme \xab naturels \xbb, l\xe9gitiment leur position de sup\xe9riorit\xe9."})})]})]}),"\n",(0,i.jsx)(t.h2,{id:"la-relativit\xe9-du-beau--v\xe9nus",children:"La relativit\xe9 du beau : V\xe9nus"}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.th,{children:"Exercice sur les repr\xe9sentations de V\xe9nus"})})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsx)(t.strong,{children:"Expliquez en quoi les diff\xe9rentes repr\xe9sentations de V\xe9nus nous prouvent la relativit\xe9 du beau."})})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:"Les trois repr\xe9sentations de V\xe9nus, r\xe9parties sur des mill\xe9naires, illustrent la relativit\xe9 du beau de mani\xe8re frappante."})}),(0,i.jsx)(t.tr,{children:(0,i.jsxs)(t.td,{children:["La ",(0,i.jsx)(t.strong,{children:"V\xe9nus de Willendorf"})," (Pal\xe9olithique, environ 25 000 av. J.-C.) pr\xe9sente un corps aux formes extr\xeamement g\xe9n\xe9reuses, avec des seins et des hanches hypertrophi\xe9s. La beaut\xe9 est ici li\xe9e \xe0 la f\xe9condit\xe9 et \xe0 la survie de l\u2019esp\xe8ce."]})}),(0,i.jsx)(t.tr,{children:(0,i.jsxs)(t.td,{children:["La ",(0,i.jsx)(t.strong,{children:"Naissance de V\xe9nus"})," de Botticelli (1485) incarne l\u2019id\xe9al de la Renaissance italienne : un corps \xe9lanc\xe9, une peau claire, des cheveux blonds ondulants. La beaut\xe9 est associ\xe9e \xe0 l\u2019harmonie des proportions, \xe0 la gr\xe2ce et \xe0 l\u2019id\xe9alisation du corps f\xe9minin."]})}),(0,i.jsx)(t.tr,{children:(0,i.jsxs)(t.td,{children:["La ",(0,i.jsx)(t.strong,{children:"Black Venus"})," de Niki de Saint Phalle (1965) rompt avec ces canons : sculpture monumentale en polyester peint, elle repr\xe9sente un corps f\xe9minin noir aux formes rondes et joyeuses. L\u2019\u0153uvre revendique une beaut\xe9 li\xe9e \xe0 l\u2019engagement politique (solidarit\xe9 avec les droits civiques des Afro-Am\xe9ricains) et \xe0 la lib\xe9ration des normes esth\xe9tiques traditionnelles."]})}),(0,i.jsx)(t.tr,{children:(0,i.jsx)(t.td,{children:(0,i.jsx)(t.strong,{children:"Ces trois \u0153uvres montrent que la beaut\xe9 n\u2019ob\xe9it pas \xe0 des crit\xe8res universels et intemporels : elle varie selon les \xe9poques, les cultures et les intentions des artistes."})})})]})]})]})}function c(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}}}]);